this.suit = suit;
this.name = name;
this.value = value;
this.hidden = false; // Change this line to make cards revealed by default
}

public int getValue() {
return value;
}

public void reveal() {
this.hidden = false;
}

public boolean isHidden() {
return hidden;
}

